text:
{
  "formal_minutes": {
    "회의_메타": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 일정",
        "decision": "스모크 테스트 통과를 조건으로 금요일 15:00 KST를 공개 릴리스 목표 시각으로 둔다.",
        "basis": "수요일 릴리스 제안에 이의가 있었고, 최종적으로 금요일 15:00 KST 조건부 목표가 확정되었다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 거부되었다."
      }
    ],
    "rejected_proposals": [
      {
        "topic": "수요일 공개 릴리스",
        "proposal": "수요일에 릴리스하자",
        "result": "거부 또는 미채택",
        "reason": "스모크 테스트 선통과 조건이 우선되었다."
      },
      {
        "topic": "mismatch 무시 처리",
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경하자",
        "result": "거부",
        "reason": "문제 발생 시 우선 package config를 점검하기로 결정했다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 골",
        "note": "공개 릴리스 확정 일정이 아니라 내부 목표로만 언급되었다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견이 있었으나, 담당자 확정은 없었다."
      },
      {
        "topic": "릴리스 노트에 수요일 스트레치 골을 기재할지 여부",
        "note": "질문은 제기되었으나 결론이 나지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급해야 하는가?",
        "status": "open"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 금요일 12:00 KST까지 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "proposed_without_owner",
      "source_certainty": "confirmed_but_unassigned"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과 통과 여부를 먼저 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 failure triage note 작성 완료 여부를 확인한다.",
      "README 설치 절차 검토의 실제 담당자가 지정되었는지 확인한다.",
      "최종 릴리스 승인 권한자 결정 여부를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 골을 기재할지 결정되었는지 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "지정되지 않은 담당자",
      "명시되지 않은 마감 시한"
    ],
    "separation_rule": "확정 결정, 거부된 제안, 내부 스트레치 골, 리스크, 미해결 질문은 서로 분리하여 기록한다."
  },
  "non_invention_rules": [
    "고객 정보를 발명하지 않는다.",
    "예산 사실을 추가하지 않는다.",
    "보안 사고를 추정하지 않는다.",
    "프로덕션 장애를 추정하지 않는다.",
    "법무 승인 필요성을 추가하지 않는다.",
    "명시되지 않은 owner를 임의 지정하지 않는다.",
    "명시되지 않은 deadline을 임의 확정하지 않는다.",
    "제공된 합성 회의 메모 범위를 넘는 참조 출력이나 정답 예시를 사용하지 않는다."
  ]
}
